import logging
import os
from pathlib import Path
from typing import Optional

from flask import Flask, request, jsonify

app = Flask(__name__)

LOG_DIR = Path(os.getenv("LOG_DIR", "logs"))
LOG_DIR.mkdir(parents=True, exist_ok=True)
LOG_FILE = LOG_DIR / os.getenv("LOG_FILE", "application.log")

logger = logging.getLogger("centralized_web_logger")
logger.setLevel(logging.INFO)
handler = logging.FileHandler(LOG_FILE, encoding="utf-8")
handler.setLevel(logging.INFO)
handler.setFormatter(logging.Formatter("%(asctime)s %(levelname)s %(message)s"))
logger.addHandler(handler)
logger.propagate = False


def _get_client_ip() -> str:
    forwarded_for = request.headers.get("X-Forwarded-For", "")
    if forwarded_for:
        return forwarded_for.split(",")[0].strip()
    return request.remote_addr or "unknown"


def _coerce_level(level: Optional[str]) -> int:
    if not level:
        return logging.INFO
    level = level.upper()
    return {
        "DEBUG": logging.DEBUG,
        "INFO": logging.INFO,
        "WARNING": logging.WARNING,
        "ERROR": logging.ERROR,
        "CRITICAL": logging.CRITICAL,
    }.get(level, logging.INFO)


@app.post("/log")
def write_log():
    data = request.get_json(silent=True) or {}
    message = data.get("message", "")
    service = data.get("service", "unknown-service")
    level_name = data.get("level", "INFO")
    request_id = data.get("request_id", request.headers.get("X-Request-ID", ""))
    client_ip = _get_client_ip()
    user_agent = request.headers.get("User-Agent", "")

    if not isinstance(message, str) or not message.strip():
        return jsonify({"error": "message is required"}), 400

    level = _coerce_level(level_name)

    logger.log(
        level,
        "service=%s request_id=%s client_ip=%s user_agent=%s message=%s",
        service,
        request_id,
        client_ip,
        user_agent,
        message,
    )

    return jsonify({"status": "logged"}), 200


